function ensureDefaultInventoryRooms(boxes) {
  const byId = new Map(boxes.map((b) => [b.id, b]));
  DEFAULT_INVENTORY_ROOMS.forEach(({ id, name }) => {
    if (!byId.has(id)) boxes.push({ id, name, parentId: null, createdAt: new Date().toISOString() });
  });
  return boxes;
}

function normalizeInventoryRoomVisibility(raw) {
  const result = {};
  DEFAULT_INVENTORY_ROOMS.forEach(({ id }) => { result[id] = raw?.[id] !== false; });
  return result;
}

function normalizeShowtimesData(raw) {
  if (!raw || typeof raw !== "object") return {};
  const TWELVE_HOURS = 12 * 60 * 60 * 1000;
  const now = Date.now();
  const out = {};
  for (const [id, entry] of Object.entries(raw)) {
    if (Array.isArray(entry?.data) && entry.fetchedAt && (now - entry.fetchedAt) < TWELVE_HOURS) {
      out[id] = { data: entry.data, fetchedAt: entry.fetchedAt };
    }
  }
  return out;
}

function normalizeRecreateHobbies(h) {
  const defaults = { sailing: true, piano: true };
  if (!h || typeof h !== "object") return { ...defaults };
  return {
    sailing: h.sailing !== false,
    piano: h.piano !== false,
  };
}

