    vesselName: e?.vesselName || "",
    departurePort: e?.departurePort || "",
    arrivalPort: e?.arrivalPort || "",
    waters: e?.waters || "",
    distanceNm: e?.distanceNm != null ? Number(e.distanceNm) : null,
